/// PROCESS-PF8-KEY
fn p_process_pf8_key(state: &mut ProgramState) {
    state.ws_variables.ws_acct_id = state.carddemo_commarea.cdemo_account_info.cdemo_acct_id.clone();
    state.ws_variables.ws_auth_key = FixedString::copy_from(&state.carddemo_commarea.cdemo_cpvd_info.cdemo_cpvd_pau_selected);
    p_read_auth_record(state);
    p_read_next_auth_record(state);
    if state.ws_ims_variables.ws_ims_psb_schd_flg == "Y" {
        state.ws_ims_variables.ws_ims_psb_schd_flg = "N".into();
        p_take_syncpoint(state);
    }
    if state.ws_variables.ws_auths_eof == "Y" {
        state.ws_variables.ws_send_erase_flg = "N".into();
        state.ws_variables.ws_message = "Already at the last Authorization...".into();
    } else {
        state.carddemo_commarea.cdemo_cpvd_info.cdemo_cpvd_pau_selected = FixedString::copy_from(&state.pending_auth_details.pa_authorization_key);
        p_populate_auth_details(state);
    }
}

